import React, { useEffect, useState } from "react";
import '../styles/debt-table.css';
import { getDebts } from "../services/debtService";

export default function DebtTable() {
    const [debts, setDebts] = useState([]);
    const [error, setError] = useState("");
  //const debts = getDebts(1);

/*
  const debts = [
    {
      id: 1,
      customerId: 1001,
      currentBalance: 2500.75,
      creditor: "Barclays",
      debtStatusId: 2
    },
    {
      id: 2,
      customerId: 1002,
      currentBalance: 1200.0,
      creditor: "HSBC",
      debtStatusId: 1
    },
    {
      id: 3,
      customerId: 1003,
      currentBalance: 4500.5,
      creditor: "NatWest",
      debtStatusId: 3
    }
  ];
*/

    useEffect(() => {
        loadDebts();
    }, []);

    async function loadDebts() {
        try {
            const data = await getDebts(101);
            setDebts(data);
        } catch (err) {
            setError(err.message);
        } finally {
           // setLoading(false);
        }
    }

{error && <p>{error}</p>}

  return (

    
    <div className="container">
      <h2>Debt Details</h2>

      <table className="debt-table">
        <thead>
          <tr>
            <th>Id</th>
            <th>Customer Id</th>
            <th>Current Balance</th>
            <th>Creditor</th>
            <th>Debt Status Id</th>
          </tr>
        </thead>

        <tbody>
          {debts.map((debt) => (
            <tr key={debt.id}>
              <td>{debt.id}</td>
              <td>{debt.customerId}</td>
              <td>0.00</td>

              

              <td>{debt.creditor}</td>
              <td>{debt.debtStatusId}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
